import { useState, useEffect, useRef } from "react";

const SpeedyAlphabet = () => {
  const [typedText, setTypedText] = useState("");
  const [startTyping, setStartTyping] = useState(false);
  const [startTime, setStartTime] = useState(null);
  const [elapsedTime, setElapsedTime] = useState("0.00");
  const [timerRunning, setTimerRunning] = useState(false);
  const intervalRef = useRef(null);
  const inputRef = useRef(null);
  const [alphabetTimes, setAlphabetTimes] = useState([]);
  const [highScores, setHighScores] = useState([]); // Initialize state for leaderboard scores
  const [loading, setLoading] = useState(true); // Loading state for async fetch

  useEffect(() => {
    // Fetch the leaderboard when the component is mounted
    const fetchLeaderboard = async () => {
      try {
        const response = await fetch(
          "https://a-to-z-server-oa7r.onrender.com/api/scores",
        );
        if (response.ok) {
          const scores = await response.json();
          console.log("Fetched scores:", scores); // Log to verify the response

          // Sort the scores by time (ascending) and take the top 3
          const topScores = scores.sort((a, b) => a.time - b.time).slice(0, 3);
          setHighScores(topScores); // Set the top 3 scores to state
        } else {
          console.error("Failed to fetch leaderboard");
        }
      } catch (error) {
        console.error("Error fetching leaderboard:", error);
      } finally {
        setLoading(false); // Set loading to false after fetching
      }
    };

    fetchLeaderboard();

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, []);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  useEffect(() => {
    const handleKey = (e) => {
      if (e.key === "Tab") {
        e.preventDefault();
        handleReset();
        inputRef.current?.focus();
      }
    };

    window.addEventListener("keydown", handleKey);
    return () => window.removeEventListener("keydown", handleKey);
  }, []);

  const startTimer = (startTs) => {
    if (!timerRunning) {
      const now = startTs ?? Date.now();
      setStartTime(now);
      setTimerRunning(true);
      intervalRef.current = setInterval(() => {
        setElapsedTime(((Date.now() - now) / 1000).toFixed(2));
      }, 16);
    }
  };

  const stopTimer = () => {
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
    setTimerRunning(false);
  };

  const handleInputChange = (e) => {
    const inputValue = e.target.value;

    if (inputValue.length > 0) {
      const currentChar = inputValue[inputValue.length - 1].toLowerCase();

      if (!startTyping && inputValue.length > 0) {
        setStartTyping(true);
      }

      if (typedText.length === 0) {
        setElapsedTime("0.00");
      }

      if (currentChar === nextExpectedChar()) {
        let baseTime = startTime;

        if (!timerRunning) {
          const now = Date.now();
          startTimer(now);
          baseTime = now;
        }

        const currentTime = (Date.now() - baseTime) / 1000;

        setAlphabetTimes((prevTimes) => [...prevTimes, currentTime]);

        if (inputValue === "abcdefghijklmnopqrstuvwxyz") {
          stopTimer();
          const totalTime = (Date.now() - (startTime ?? Date.now())) / 1000;
          setElapsedTime(totalTime.toFixed(2));
          updateHighScores(totalTime); // Check if this score qualifies for top 3
        }

        setTypedText(inputValue);
      } else {
        // ignore wrong input but keep cursor responsive
        return;
      }
    } else {
      setStartTyping(false);
    }
  };

  const nextExpectedChar = () => {
    const alphabet = "abcdefghijklmnopqrstuvwxyz";
    return alphabet[typedText.length];
  };

  const updateHighScores = (newTime) => {
    const qualifiesForTop3 =
      highScores.length < 3 ||
      parseFloat(newTime) < parseFloat(highScores[2]?.time);

    if (qualifiesForTop3) {
      const newScore = { name: "You", time: parseFloat(newTime) };

      const updatedScores = [...highScores, newScore]
        .sort((a, b) => a.time - b.time)
        .slice(0, 3);

      setHighScores(updatedScores);
    }
  };

  const handleReset = () => {
    setTypedText("");
    setElapsedTime("0.00");
    setStartTime(null);
    setTimerRunning(false);
    setStartTyping(false);
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
    setAlphabetTimes([]);
  };

  return (
    <div className="min-h-screen bg-[#f5f6f8] text-[#1c1f23] flex flex-col font-['Inter']">
      {/* HEADER */}
      <div className="flex justify-between items-center px-10 py-6 border-b border-gray-200">
        <div className="flex items-center gap-8">
          <h1 className="font-['Space Grotesk'] font-bold tracking-wide text-lg">
            ALPHATYPE
          </h1>
          <div className="flex gap-6 text-sm">
            <span className="text-blue-600 font-medium">DASHBOARD</span>
            <span className="text-gray-400">PRACTICE</span>
            <span className="text-gray-400">LEADERBOARDS</span>
          </div>
        </div>
        <div className="flex gap-4 text-gray-500 text-lg">⚙️ 👤</div>
      </div>

      {/* MAIN */}
      <div className="flex flex-1 px-12 py-10 gap-10">
        {/* SIDEBAR */}
        <div className="w-96 space-y-10">
          <div>
            <p className="text-xs tracking-widest text-gray-400 mb-3 font-['Space Grotesk']">
              SESSION SUMMARY
            </p>

            <div className="bg-white p-5 rounded-none border border-gray-100 mb-4">
              <p className="text-xs text-gray-400">CURRENT SPEED</p>
              <p className="text-3xl font-bold text-blue-600">
                84 <span className="text-sm text-gray-400">WPM</span>
              </p>
            </div>

            <div className="bg-white p-5 rounded-none border border-gray-100">
              <p className="text-xs text-gray-400">HIGHEST ACCURACY</p>
              <p className="text-3xl font-bold text-green-600">
                98.4 <span className="text-sm text-gray-400">%</span>
              </p>
            </div>
          </div>

          <div>
            <p className="text-xs tracking-widest text-gray-400 mb-3 font-['Space Grotesk']">
              GLOBAL RANKING
            </p>
            <div className="bg-white border border-gray-100 rounded-none p-4 text-sm">
              {loading ? (
                <p className="text-gray-400">Loading...</p>
              ) : (
                highScores.map((entry, i) => (
                  <div key={i} className="flex justify-between py-1">
                    <span>{entry.name}</span>
                    <span>{entry.time.toFixed(1)}s</span>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>

        {/* MAIN PANEL */}
        <div className="flex-1">
          {/* TYPING BOX */}
          <div
            className="bg-[#dfe5ea] rounded-none px-12 py-14 cursor-text"
            onClick={() => inputRef.current?.focus()}
          >
            <div className="flex justify-end gap-12 mb-6">
              <div className="text-right">
                <p className="text-[10px] tracking-widest text-gray-400 font-['Space Grotesk']">
                  TIMER
                </p>
                <p className="text-lg font-['Space Grotesk'] text-gray-800">
                  {elapsedTime}
                </p>
              </div>

              <div className="text-right">
                <p className="text-[10px] tracking-widest text-gray-400 font-['Space Grotesk']">
                  MISSED
                </p>
                <p className="text-xl font-['Space Grotesk'] text-red-500">
                  02
                </p>
              </div>
            </div>

            <div className="text-center text-[64px] font-['Space Grotesk'] font-normal leading-[1.5] space-y-5">
              {["abcdefghij", "klmnopqrst", "uvwxyz"].map((row, rowIndex) => (
                <div key={rowIndex} className="flex justify-center gap-4">
                  {row.split("").map((letter, colIndex) => {
                    const index =
                      rowIndex === 0
                        ? colIndex
                        : rowIndex === 1
                          ? colIndex + 10
                          : colIndex + 20;

                    const isDone = index < typedText.length;
                    const isNext = index === typedText.length;

                    return (
                      <span
                        key={index}
                        className={`
                          transition-all duration-150
                          ${
                            isDone
                              ? "text-[#2a2f33]"
                              : isNext
                                ? "text-[#1c1f23] underline underline-offset-4"
                                : "text-[#a0a6ac]"
                          }
                        `}
                      >
                        {letter}
                      </span>
                    );
                  })}
                </div>
              ))}
            </div>

            <input
              ref={inputRef}
              type="text"
              value={typedText}
              onChange={handleInputChange}
              className="opacity-0 absolute"
              autoFocus
            />

            <div className="text-center mt-10 text-[11px] text-gray-500 tracking-wide">
              <span className="px-2 py-1 bg-gray-200 rounded-none text-gray-600 font-['Inter']">
                TAB
              </span>
              <span className="ml-3">PRESS TO RESTART</span>
            </div>
          </div>

          {/* LATENCY SECTION (static for now) */}
          <div className="mt-12">
            <p className="text-xs tracking-widest text-gray-400 mb-4 font-['Space Grotesk']">
              CHARACTER LATENCY ANALYSIS
            </p>

            <div className="grid grid-cols-9 gap-5 text-xs">
              {"ABCDEFGHI".split("").map((l, i) => (
                <div
                  key={i}
                  className="bg-white border border-gray-100 rounded-none p-3 text-center"
                >
                  <p className="text-gray-500">{l}</p>
                  <p className="text-gray-700">--</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* FOOTER */}
      <div className="flex justify-between px-8 py-4 text-xs text-blue-500 border-t border-gray-100">
        <span className="font-['Space Grotesk']">© 2024 BY UNLINKLY.COM.</span>
        <div className="flex gap-6">
          <span className="text-gray-400">v2.0</span>
        </div>
      </div>
    </div>
  );
};

export default SpeedyAlphabet;
